const CONFIG = {
  GOOGLE_SHEET_ID:  'TU_SHEET_ID_AQUI',      // Mismo Sheet que en el workflow de outreach
  CALENDLY_LINK:    'https://calendly.com/alejandro-agutidesigns/30min',
  REMITENTE_NOMBRE: 'Alejandro | AgutiDesigns',
  REMITENTE_EMAIL:  'alejandro@agutidesigns.io',
  WEB_AGUTI:        'https://agutidesigns.io',
  WHATSAPP:         '+34 625 204 337'
};
return [{ json: CONFIG }];

// Filtra clínicas que necesitan un seguimiento HOY
// Secuencia: día 3 → follow-up 1 | día 7 → follow-up 2 | día 12 → follow-up 3 (último aviso)

const config = $('⚙️ Config').first().json;
const hoy    = new Date();
hoy.setHours(0, 0, 0, 0);

const conSeguimiento = $input.all()
  .map(item => {
    const d = item.json;
    const nSeg   = parseInt(d['Nº seguimientos'] || '0');
    const estado = d.Estado || '';

    // Solo clínicas contactadas, con email, que no hayan cerrado/respondido
    if (!d.Email || !d.Email.includes('@')) return null;
    if (!['Contactado', 'Seguimiento 1', 'Seguimiento 2'].includes(estado)) return null;
    if (nSeg >= 3) return null; // Ya se enviaron los 3 follow-ups

    // Calcular días desde el contacto
    const fechaRef = d['Fecha último contacto'] || d['Fecha contacto'];
    if (!fechaRef) return null;

    const fecha    = new Date(fechaRef);
    fecha.setHours(0, 0, 0, 0);
    const diasDesde = Math.floor((hoy - fecha) / (1000 * 60 * 60 * 24));

    // ¿Le toca seguimiento hoy?
    const ventana = [
      { min: 3, max: 5,  num: 1, tipo: 'Seguimiento 1' },  // día 3-5
      { min: 7, max: 9,  num: 2, tipo: 'Seguimiento 2' },  // día 7-9
      { min: 12, max: 14, num: 3, tipo: 'Último aviso' }   // día 12-14
    ];

    const accion = ventana.find(v =>
      nSeg === v.num - 1 &&
      diasDesde >= v.min &&
      diasDesde <= v.max
    );

    if (!accion) return null;

    return {
      json: {
        ...d,
        _numSeguimiento: accion.num,
        _tipoSeguimiento: accion.tipo,
        _diasDesde: diasDesde,
        _config: config
      }
    };
  })
  .filter(Boolean);

if (conSeguimiento.length === 0) {
  throw new Error(`Sin seguimientos para hoy (${hoy.toLocaleDateString('es-ES')}). Vuelve mañana.`);
}

return conSeguimiento;

const item   = $('🔄 Un seguimiento a la vez').item.json;
const config = item._config;
const num    = item._numSeguimiento;

// ── Prompts diferentes según el número de seguimiento ────
const prompts = {
  1: {
    contexto: `Es el primer seguimiento (3-5 días después del primer email).
    Estrategia: ofrecer valor gratuito. Menciona que tienes listo un análisis SEO de 5 minutos para su clínica.
    Referencia el email anterior de forma natural. Sé breve (80-100 palabras). Nada agresivo.`,
    asunto_base: `RE: sobre la web de ${item.Nombre}`
  },
  2: {
    contexto: `Es el segundo seguimiento (7-9 días desde el primer contacto).
    Estrategia: prueba social. Menciona una clínica dental (ficticia pero creíble) en su misma ciudad que
    mejoró sus resultados. Algo como: "La semana pasada una clínica en ${item.Ciudad} consiguió X nuevas
    citas al mes tras optimizar su web y su ficha de Google".
    Breve (80-100 palabras). Termina con el link de Calendly.`,
    asunto_base: `Caso real: clínica en ${item.Ciudad} +40% citas online`
  },
  3: {
    contexto: `Es el tercer y último email (12-14 días desde el primer contacto).
    Estrategia: cierre de puerta. Hazlo muy corto (50-70 palabras). Di que cierras la agenda para nuevos
    proyectos este mes y que si no les interesa está bien, solo quieres saber.
    Tono: natural, sin presión, como un colega que hace una última pregunta.
    NO menciones problemas, solo la oportunidad de una llamada rápida.`,
    asunto_base: `Última pregunta — ${item.Nombre}`
  }
};

const p = prompts[num] || prompts[1];

const systemPrompt = `Eres el asistente de ventas de AgutiDesigns, agencia de marketing para clínicas dentales.
Firmas como Alejandro.

${p.contexto}

Devuelve SOLO JSON válido:
{
  "asunto": "string",
  "cuerpo_html": "string (HTML con etiquetas <p>)"
}`;

const userPrompt = `Clínica: ${item.Nombre} (${item.Ciudad})
Email anterior enviado hace ${item._diasDesde} días
Último asunto enviado: ${item['Asunto enviado'] || 'análisis web personalizado'}
Nombre contacto: equipo de la clínica (no tenemos nombre personal)
Link Calendly: ${config.CALENDLY_LINK}
Firma: ${config.REMITENTE_NOMBRE} · ${config.WEB_AGUTI} · ${config.WHATSAPP}`;

return [{
  json: {
    ...item,
    _systemPrompt: systemPrompt,
    _userPrompt:   userPrompt,
    _asuntoBase:   p.asunto_base
  }
}];

const gptJson = $input.first().json;
const prev    = $('✍️ Preparar email de seguimiento').item.json;
const config  = prev._config;

let emailData;
try {
  const raw   = gptJson.choices?.[0]?.message?.content || '{}';
  const match = raw.match(/\{[\s\S]*\}/);
  emailData = JSON.parse(match ? match[0] : raw);
} catch(e) {
  emailData = {
    asunto:      prev._asuntoBase,
    cuerpo_html: `<p>Hola,</p><p>Solo quería hacer un seguimiento de mi email anterior. ¿Tenéis 30 minutos para una llamada rápida?</p><p><a href="${config.CALENDLY_LINK}">Reservar llamada →</a></p>`
  };
}

const htmlFinal = `<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><style>
  body{font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#222;line-height:1.65;font-size:15px}
  .wrap{padding:32px 28px}
  .cta-btn{display:inline-block;background:#0044FF;color:#fff!important;padding:12px 26px;border-radius:8px;text-decoration:none;font-weight:700;margin:16px 0}
  .footer{border-top:1px solid #eee;padding:16px 28px;font-size:11px;color:#999}
  .footer a{color:#0044FF}
</style></head>
<body>
  <div class="wrap">
    ${emailData.cuerpo_html}
    <a href="${config.CALENDLY_LINK}" class="cta-btn">📅 Reservar llamada de 30 min →</a>
  </div>
  <div class="footer">
    ${config.REMITENTE_NOMBRE} · <a href="${config.WEB_AGUTI}">${config.WEB_AGUTI}</a> · ${config.WHATSAPP}
    <br><span style="font-size:9px">Para darte de baja responde con asunto BAJA. RGPD · LSSI-CE art.21.2</span>
  </div>
</body></html>`;

return [{
  json: {
    _to:             prev.Email,
    _asunto:         emailData.asunto,
    _html:           htmlFinal,
    _numSeguimiento: prev._numSeguimiento,
    _tipoSeguimiento: prev._tipoSeguimiento,
    _rowEmail:       prev.Email,
    _sheetId:        config.GOOGLE_SHEET_ID
  }
}];
